3	import { processScenario, type Scenario } from "./claim-office.js";
4	
5	let scenarioJson = "";
6	process.stdin.setEncoding("utf8");
7	for await (const chunk of process.stdin) {
8	  scenarioJson += chunk;
9	}
10	
11	try {
12	  const scenario: Scenario = JSON.parse(scenarioJson);
13	  process.stdout.write(JSON.stringify(processScenario(scenario)));
14	} catch (error) {
15	  process.stderr.write((error as Error).message);
16	  process.exitCode = 1;
17	}
